			severity warning;
		if saturate = Sat_s or saturate = SatWarn_s then
			a_v := max (min (a_v, 2**result_fmt.IntBits-1), 0);
		end if;
		result_v (result_v'high downto result_fmt.FracBits) := 
			std_logic_vector(to_unsigned (a_v, result_fmt.IntBits));
	end if;
	return result_v;
end;

